/**
 * Builds every distributed workspace twice and compares generated bytes.
 *
 * @module
 */

import { spawn } from 'node:child_process';
import { createHash } from 'node:crypto';
import { readFile, readdir } from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const scriptsRoot = path.dirname(fileURLToPath(import.meta.url));
const repositoryRoot = path.resolve(scriptsRoot, '..');
const npmCliPath = process.env.npm_execpath;
const outputRoots = ['dist', 'packages/image-editor-codemod/dist'];

if (!npmCliPath) throw new Error('npm_execpath is unavailable; run through an npm script.');

function runNpm(scriptName) {
    return new Promise((resolve, reject) => {
        const child = spawn(process.execPath, [npmCliPath, 'run', scriptName], {
            cwd: repositoryRoot,
            stdio: 'inherit',
            windowsHide: true,
        });
        child.on('error', reject);
        child.on('close', (code, signal) => {
            if (signal) reject(new Error(`${scriptName} terminated by ${signal}.`));
            else if (code === 0) resolve();
            else reject(new Error(`${scriptName} exited with code ${code}.`));
        });
    });
}

async function collectFiles(directory) {
    const entries = await readdir(directory, { withFileTypes: true });
    const files = [];
    for (const entry of entries) {
        const entryPath = path.join(directory, entry.name);
        if (entry.isDirectory()) files.push(...(await collectFiles(entryPath)));
        else if (entry.isFile()) files.push(entryPath);
    }
    return files;
}

async function outputManifest() {
    const manifest = {};
    for (const root of outputRoots) {
        for (const filePath of await collectFiles(path.join(repositoryRoot, root))) {
            const relativePath = path.relative(repositoryRoot, filePath).replaceAll('\\', '/');
            const bytes = await readFile(filePath);
            manifest[relativePath] = {
                bytes: bytes.length,
                sha256: createHash('sha256').update(bytes).digest('hex'),
            };
        }
    }
    return manifest;
}

async function buildAll() {
    await runNpm('build');
    await runNpm('build:codemod');
    return outputManifest();
}

const first = await buildAll();
const second = await buildAll();
const firstText = JSON.stringify(first);
const secondText = JSON.stringify(second);
if (firstText !== secondText) {
    const paths = new Set([...Object.keys(first), ...Object.keys(second)]);
    const changed = [...paths].filter(
        (filePath) => JSON.stringify(first[filePath]) !== JSON.stringify(second[filePath]),
    );
    throw new Error(`Generated output is not deterministic: ${changed.join(', ')}.`);
}

console.log(`Deterministic build passed (${Object.keys(first).length} generated files).`);
